module.render:
const rawClasses = (sections[0] || '').trim();
const inner = (sections[1] || '').trim();
// Forgiving: with no second section (missing `<!-- @ -->` separator), the
// single section is the CONTENT, not a class list — otherwise content put
// there would be swallowed / dropped.
if (!inner) {
  return `\n\n${rawClasses}\n\n`;
}
// Sanitize: keep only class-name-safe chars (letters, digits, _, -, space),
// collapse whitespace. Prevents breaking out of the class attribute.
const classes = rawClasses
  .replace(/[^\w\- ]+/g, ' ')
  .split(/\s+/)
  .filter(Boolean)
  .join(' ');
const classAttr = classes ? ` class="${classes}"` : '';
return `\n\n<div${classAttr}>\n\n${inner}\n\n</div>\n\n`;
